case 'PJ0301':
case 'PJ0302':
case 'PJ0304':
case 'PJ0305':
case 'PJ0306':
urln = url2;
break;
default:
urln = url1;
break;
}
}
if (comKaime.kimIfExist() == true || comKaime.kimGetNoSetKaimeGroup() != null){
comDialog.confirm('編集中の買い目は破棄されますがよろしいですか。', function(){
comKaime.kimClear();
hhPostRace(fid,prm,urln);
return;
}, function(){
return;
});
} else {
hhPostRace(fid,prm,urln);
return;
}
}
};
